import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"16. Types Of Employment","description":"","frontmatter":{"title":"16. Types Of Employment","eba":"Medical Specialists 2022-2026","topics":["hours","wages","employment"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/16-types-of-employment.md","filePath":"ebas/medical-specialists/employment/16-types-of-employment.md"}'),n={name:"ebas/medical-specialists/employment/16-types-of-employment.md"};function i(r,e,l,p,c,m){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_16-types-of-employment" tabindex="-1">16. Types Of Employment <a class="header-anchor" href="#_16-types-of-employment" aria-label="Permalink to &quot;16. Types Of Employment&quot;">​</a></h1><p>Doctors will be employed in Full-time or Fractional Employment.</p><p><strong>16.1</strong> Full-Time Employment</p><p><strong>(a)</strong> A Full-time Doctor is one who is engaged to work 38 hours per week or an average of 38 hours as per subclause 28.1 (Hours of Work), plus reasonable additional hours.</p><p><strong>(b)</strong> Provided a Full-time Doctor is ready, willing and able to work full-time hours, the Doctor will be paid the weekly salary appropriate to the Doctor’s classification.</p><p><strong>16.2</strong> Fractional Employment</p><p>A Fractional Doctor is one who is engaged by a Health Service to work 35 hours per week or less, for the treatment of Health Service patients and other agreed duties/commitments.</p><p><strong>16.3</strong> Fixed term employment</p><p><strong>(a)</strong> Full-time or Fractional employment may be for a fixed (maximum) term or ongoing.</p><p><strong>(b)</strong> For the purpose of this Agreement, fixed term employment includes a maximum term contract; that is, a contract for a fixed period that is terminable by notice within the contract period.</p><p><strong>(c)</strong> Fixed term employment will only be used to meet genuine fixed term needs.</p><p><strong>(i)</strong> Genuine fixed term needs include, but are not limited to:</p><p>A. a replacement for a Doctor on a period of absence;</p><p>B. undertaking a specified task which is funded for a specified period;</p><p>C. for the first year of employment with the Health Service.</p><p><strong>(ii)</strong> In addition to subclause 16.3(i) above, a Health Service may offer a Doctor a fixed term of employment where:</p><p>A. the Doctor’s employment is dependent upon their holding of an appropriate immigration visa – in such case, the Health Service may offer the Doctor a period of employment commensurate with the term of the visa held; or</p><p>B. the Doctor holds limited registration to practise as a medical practitioner, or where conditions have been placed on the Doctor’s registration – in such case, the Health Service may offer the Doctor a fixed term of employment consistent with the Doctor’s type of, or conditions upon, registration.</p><p><strong>(d)</strong> Nothing in this clause disrupts existing fixed term or maximum term contracts that exist at the commencement date of this Agreement.</p><p><strong>(e)</strong> This clause should be read in conjunction with subclause 54.2(a).</p><p><strong>16.4</strong> Internal Locum</p><p><strong>(a)</strong> Purpose</p><p>The purpose of the Internal Locums (however titled) is to support Health Services access a prepared supply of employed labour to meet fluctuations in supply (such as those arising from unplanned absence) or demand (such as a greater than anticipated number of patients) or for specialised needs, rather than the use of external contractors where possible.</p><p><strong>(b)</strong> Definition</p><p>An Internal Locum:</p><p><strong>(i)</strong> is a Doctor who:</p><p>A. is made an offer of employment on the basis that the Employer makes no firm advance commitment to continuing and indefinite work according to an agreed pattern of work (e.g. relief work such as replacing a Doctor on an unplanned absence); and</p><p>B. accepts the offer of employment on that basis; and</p><p>C. is an Employee as a result of that acceptance;</p><p><strong>(ii)</strong> is not a Doctor who could reasonably be employed on a Full Time or Fractional basis under this Agreement.</p><p><strong>(c)</strong> Subject to the minimum engagement period (or payment in lieu of), an Internal Locum’s engagement is terminable without prior notice by either party.</p><p><strong>(d)</strong> The minimum shift length for an Internal Locum is three and a half hours.</p><p><strong>(e)</strong> An Internal Locum will be paid the hourly rate for:</p><p><strong>(i)</strong> a Fractional Specialist 10.6 – 14 hours per week for the Doctor’s classification plus 25% until FFPPOA 1 July 2022, then;</p><p><strong>(ii)</strong> a Fractional Specialist 10.6 – 17.5 hours per week for the Doctor’s classification plus 25% from FFPPOA 1 July 2022 onwards.</p><p>Payments for shift work (<a href="/eba/ebas/medical-specialists/wages/36-shift-penalty-payments.html">clause 36</a>), Saturdays and Sundays (<a href="/eba/ebas/medical-specialists/wages/36-shift-penalty-payments.html">clause 36</a>) and penalty payments for Public Holidays worked (<a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a>) also apply to Internal Locums.</p><p><strong>(f)</strong> Except where expressly excluded, an Internal Locum will be entitled to receive the allowances prescribed by Part F of this Agreement.</p><p><strong>(g)</strong> The following provisions do not apply to Internal Locums:</p><p><strong>(i)</strong> annual leave (<a href="/eba/ebas/medical-specialists/leave/47-annual-leave.html">clause 47</a>);</p><p><strong>(ii)</strong> paid personal leave (<a href="/eba/ebas/medical-specialists/leave/49-personal-carer-s-leave.html">clause 49</a>);</p><p><strong>(iii)</strong> paid compassionate leave (<a href="/eba/ebas/medical-specialists/leave/50-compassionate-leave.html">clause 50</a>);</p><p><strong>(iv)</strong> paid family violence leave (<a href="/eba/ebas/medical-specialists/leave/60-family-violence-leave.html">clause 60</a>);</p><p><strong>(v)</strong> absences on defence leave (<a href="/eba/ebas/medical-specialists/leave/58A-absences-on-defence-leave.html">clause 58A</a>);</p><p><strong>(vi)</strong> continuing medical education leave (<a href="/eba/ebas/medical-specialists/leave/59-continuing-medical-education-leave.html">clause 59</a>);</p><p><strong>(vii)</strong> clinical support time (<a href="/eba/ebas/medical-specialists/employment/18-clinical-support-time.html">clause 18</a>)</p><p><strong>(viii)</strong> notice period before termination (<a href="/eba/ebas/medical-specialists/employment/23-termination-of-employment-notice-of-termination.html">clause 23</a>); and</p><p><strong>(ix)</strong> special disaster leave (<a href="/eba/ebas/medical-specialists/leave/58B-special-disaster-leave.html">clause 58B</a>).</p><p><strong>(h)</strong> An Internal Locum is entitled to the following:</p><p><strong>(i)</strong> Continuing Medical Education Support (<a href="/eba/ebas/medical-specialists/allowances/41-continuing-medical-education-support.html">clause 41</a>);</p><p><strong>(ii)</strong> unpaid personal leave for carer’s responsibilities (note ss. 102 and 103 FWA)</p><p><strong>(iii)</strong> unpaid family violence leave (note s.106A FWA);</p><p><strong>(iv)</strong> unpaid compassionate leave (note ss. 104 and 105);</p><p><strong>(v)</strong> unpaid pre-adoption leave;</p><p><strong>(vi)</strong> parental leave (subject to the eligibility requirements of that clause (<a href="/eba/ebas/medical-specialists/leave/54-parental-leave.html">clause 54</a>)); and</p><p><strong>(vii)</strong> unpaid ceremonial leave.</p>',55)])])}const u=t(n,[["render",i]]);export{h as __pageData,u as default};
